var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……흔적이 남아 있어. 벌써 여길 지나쳤나.","JPN":"……痕跡が残っている。もうここを通過したか。","ENG":"...There's a trace. She must have already passed by.","TWN":"……痕跡還在，是有經過這裡嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"빠르군. 전술적인 기조는 용병단 시절과 그대로인가.","JPN":"早いな、戦術的な基調は傭兵時代のままか。","ENG":"Quite fast. Her tactical brain remains the same from her mercenary days.","TWN":"很快啊。戰術風格和在傭兵隊時一樣嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경과 머리를 맞댔다면, 더 좋은 결과를 도출할 수 있었을 텐데.","JPN":"アレンと頭脳を合わせていれば、もっと良い結論が出せていただろうな。","ENG":"Perhaps a better result would've come out if it was discussed with Sir Allen.","TWN":"要是和艾倫卿商量一下，應該能得出更好的結果。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아쉽군. 그렇지 않나?","JPN":"惜しいな。そうは思わんか？","ENG":"What a shame. Don't you agree?","TWN":"可惜了，不是嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이런, 정말이지 기습이 안 통하는 상대란 골치 아프네요.","JPN":"やれやれ、まったく不意打ちが通用しない相手って面倒くさいものですね。","ENG":"I must say, enemies who are prepared for ambushes make things so much harder.","TWN":"哎呀，說真的，對手不吃偷襲這招還真的很讓人頭疼呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"목을 노렸는데 생채기도 못 내게 하다니, 매사에 너무 엄격하신 것 아닌가요?","JPN":"首を狙ったのに傷一つ付けさせないなんて、とことん厳しい方ですね？","ENG":"I aimed for your neck, but you wouldn't allow even the slightest slit. Don't you think you're too uptight?","TWN":"好歹也讓我象徵性地弄出些傷口吧，殿下您是不是對每件事都太過嚴格了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"중요한 단서를 이렇게 노골적으로 펼쳐 두는 건 정치에서도 하책이다.","JPN":"重要なヒントをこんなふうにあからさまに広げておくのは、政治においても下策だ。","ENG":"Being unable to conceal your intentions is a critical fault, even in politics.","TWN":"如此露骨地表露自己的目的，在政治上也是下策。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"소년, 공부가 더 필요하겠군.","JPN":"少年、さらなる勉強が必要だな。","ENG":"It is clear that you need to learn more, boy.","TWN":"年輕人，你還需要繼續學習。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"어이쿠, 제 인생 설계는 열세 살 때 이미 끝났습니다.","JPN":"おやおや、僕の人生設計は13歳の時に終わっています。","ENG":"Sorry, but my life plans were laid out the minute I turned thirteen.","TWN":"哎呀，我的人生規劃早在我十三歲時就已經做好了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"서른 살 되기 전에 현업에서 은퇴하고 분재나 가꾸면서 유유자적하게 지내는 거죠.","JPN":"30歳になる前に現職を引退して、盆栽でも育てつつ、のんびり生きていくんです。","ENG":"I plan on retiring before thirty, then live a life of peace and tranquility.","TWN":"在三十歲之前退休，養養花，悠閒自在地生活。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호오, 그거 참 소박한 꿈이로다.","JPN":"ほお、それはなんとも素朴な夢だ。","ENG":"A humble dream indeed.","TWN":"噢，這個夢想還真樸實無華啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"헌데 그렇다면 홀로 나를 알현하는 짓은 그만두는 편이 낫지 않았나?","JPN":"しかし、それなら単独で私と対峙するのは止めた方が良いのではないか？","ENG":"However, don't you think it was a foolish idea to face me by yourself?","TWN":"不過那樣的話，你是不是最好不要一個人來見我呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 그게 말이죠. 문득 재미있는 생각이 떠오르더라고요.","JPN":"はは、それがですね。ふと面白いことを思いついたといいますか。","ENG":"Ha ha. Well, an interesting idea came to mind.","TWN":"哈哈，那個，我突然有一個有趣的想法。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이전에 겪었던 상황과 묘하게 비슷한 인상이 든다고나 할까요.","JPN":"前に経験した状況と妙に似ているような感じがするといいますか。","ENG":"Let's say it's strangely similar to something I went through before.","TWN":"可以說和以前經歷的情況有著微妙的相似印象呢。"},"stage":{"bg":"MAINSTREAM_5507010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그 때도 결국에는 미나 양을 보내고 이렇게 남아 있었죠.","JPN":"あの時も結局はミナさんを行かせて、僕一人がこうして残っていました。","ENG":"I had also sent Mina away and dealt with things alone back then.","TWN":"那時候也是我送走了米娜，自己留下來斷後。"},"stage":{"bg":"MAINSTREAM_5507010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"지금 와서 생각해 보면, 누가 미리 훈련이라도 시킨 것 아닌가 싶더라고요.","JPN":"今思えば、あらかじめ誰かに訓練されていたんじゃないかという気がするんです。","ENG":"Looking back, it's almost as if someone trained me beforehand.","TWN":"現在想來，是不是有人預知一切，所以提前訓練我。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"기시감이라는 건가. 재미있는 이야기로군.","JPN":"既視感があるということか。面白い話だ。","ENG":"Deja vu, I see. Interesting.","TWN":"似曾相識嗎？很有趣的想法。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};